INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('schedule_type', 'ONE_TIME', 'Event occurs once. repeat_* columns are null.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('schedule_type', 'RECURRING', 'Event repeats. Uses repeat_interval_days and repeat_count.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('schedule_type', 'SCHEDULE_DRIVEN', 'Timing fixed by an external official schedule. Requires reference_source.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('anchor_type', 'PROGRAMME_REGISTRATION', 'Offset measured from the programme registration/entry date.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('anchor_type', 'PREVIOUS_EVENT_COMPLETION', 'Offset measured from completion of dependency_event_code.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('anchor_type', 'BIRTH_DATE', 'Offset measured from the child date of birth (immunization).') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('condition_code', 'HIGH_RISK', 'Created only for high-risk patients (e.g. PMSMA, HRP).') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('condition_code', 'FEMALE_ONLY', 'Created only for female beneficiaries (e.g. HPV).') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('condition_code', 'IF_INITIATED', 'Created only if the care stream is initiated/started.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('condition_code', 'IF_INDICATED', 'Created only if clinically indicated/required.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('condition_code', 'ON_REFERRAL', 'On-demand service created upon referral.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('workflow_action', 'COMPLETE_ACTIVITY', 'Instructs the workflow engine to mark the current Activity complete when this field is successfully answered. The only v1 value.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('next_action', 'FOLLOW_PROGRAM_SCHEDULE', 'After a SUCCESS call, continue with the existing Programme→Event→Activity schedule in Schedule_Rule; no follow-up delay.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('next_action', 'CREATE_FOLLOWUP', 'After a non-success call, create a follow-up task after followup_delay_days.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('priority', 'NORMAL', 'Standard follow-up priority.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('priority', 'HIGH', 'Elevated follow-up priority.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('priority', 'URGENT', 'Highest follow-up priority (e.g. patient hospitalised).') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('scope_level', 'GLOBAL', 'Content applies platform-wide (scope_code = ALL). Used for cross-cutting FAQs, general schemes, communication/infection-control training.') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('scope_level', 'PROGRAMME', 'Content applies to a specific Programme (scope_code = a PRG-xxx code).') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('scope_level', 'EVENT', 'Reserved: content scoped to a specific Event (scope_code = EVT-xxx). Unused in v1 (no event-level source content).') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
INSERT INTO dinc_metadata.enum_reference (enum_column, allowed_value, meaning) VALUES ('scope_level', 'ACTIVITY', 'Reserved: content scoped to a specific Activity (scope_code = ACT-xxx). Unused in v1 (no activity-level source content).') ON CONFLICT (enum_column, allowed_value) DO NOTHING;
