INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-001', 'General', 'What is CPHC?', 'CPHC is a comprehensive primary healthcare operations and care management platform designed for NHM Assam. It helps healthcare workers manage patients, care programs, follow-up activities, clinical protocols, and health outcomes.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-002', 'General', 'Who should use CPHC?', 'CPHC is designed for healthcare workers including doctors, nurses, ASHA workers, ANMs, community health officers, and supervisors.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-003', 'General', 'Is patient information confidential?', 'Yes. Patient information is protected through role-based access controls, audit logging, secure authentication, and encrypted data storage.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-004', 'Patient Care', 'How do I enroll a patient?', 'Open the Patients section, create a new patient record, enter demographic details, assign relevant programs, and save the record.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-005', 'Patient Care', 'What programs can I assign to a patient?', 'Common programs include Immunization, Maternal Health, Child Health, Diabetes, Hypertension, Mental Health, Elderly Care, TB, and other disease-specific programs.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-006', 'Patient Care', 'How do I update patient information?', 'Open the patient record, edit the required fields, and save the changes. Updates are automatically reflected across related activities and records.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-007', 'Worklist', 'What is a worklist item?', 'A worklist item is a healthcare activity assigned to a healthcare worker for a specific patient, such as a follow-up call, assessment, counseling session, or vaccination visit.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-008', 'Worklist', 'How do I track overdue activities?', 'The dashboard highlights overdue activities. You can view, prioritize, and reschedule overdue tasks as needed.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-009', 'Worklist', 'Can I assign tasks to team members?', 'Yes. Activities can be assigned to authorized team members based on their role and responsibilities.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-010', 'Guidelines', 'How do I access clinical guidelines?', 'Open the Guidebooks section and browse the available clinical protocols, disease management guides, and care pathways.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-011', 'Guidelines', 'Are clinical guidelines updated regularly?', 'Yes. Guidelines are reviewed and updated periodically based on approved public health and clinical recommendations.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-012', 'Training', 'What training modules are available?', 'Training modules may include clinical skills, patient communication, disease management, public health programs, and emergency response topics.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-013', 'Training', 'How do I complete a training module?', 'Open the Training section, select a module, review the content, complete any assessments, and submit your responses.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-014', 'FAQ', 'Where is patient data stored?', 'Patient information is stored securely in a PostgreSQL database with appropriate access controls and backup mechanisms.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-015', 'FAQ', 'Can I export patient records?', 'Authorized users can export approved data and reports based on their assigned permissions.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-016', 'FAQ', 'What should I do if I encounter an error?', 'Record the error details and notify the system administrator or support team for assistance.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-017', 'Technical', 'Which web browsers are supported?', 'Latest versions of Chrome, Firefox, Edge, and Safari are recommended for optimal performance.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-018', 'Technical', 'Can I use CPHC offline?', 'An internet connection is generally required. Offline capabilities may be available depending on future system enhancements.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-019', 'Technical', 'How often is the system maintained?', 'Maintenance activities are performed periodically. Planned maintenance schedules are communicated in advance.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-020', 'Compliance', 'How is patient data protected?', 'Patient information is protected through authentication, authorization controls, audit logs, encrypted storage, and secure communication channels.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-021', 'Compliance', 'Who can access patient information?', 'Only authorized healthcare workers with appropriate permissions can access patient information relevant to their responsibilities.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-022', 'Support', 'What should I do if I forget my password?', 'Use the password reset option or contact the system administrator for assistance.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-023', 'Support', 'How can I obtain technical support?', 'Contact your designated support team, facility administrator, or help desk for technical assistance.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-024', 'Programs', 'What is a program?', 'A program is a healthcare initiative such as Diabetes Management, Maternal Health, TB Care, or Immunization that organizes patient care activities.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-025', 'Programs', 'What is an event?', 'An event is a scheduled healthcare activity associated with a disease or program, such as an assessment, review, follow-up call, or vaccination visit.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-026', 'Programs', 'What is an outcome template?', 'An outcome template defines the form and fields used to record the outcome of a healthcare activity or patient interaction.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
INSERT INTO dinc_metadata.faq (faq_code, category, question, answer, is_active) VALUES ('FAQ-027', 'Programs', 'What is a worklist item?', 'A worklist item is a specific task generated from a program event that requires action by a healthcare worker.', TRUE) ON CONFLICT (faq_code) DO NOTHING;
