INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('f9e63aef-e210-53d5-86a1-42f063e3c64e', 'NUT-001', 'MATERNAL', 'Iron-rich foods: green leafy vegetables, lentils, beans, dates, jaggery daily', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('2ab616e1-5a62-5eb6-9a67-17d6ba666329', 'NUT-002', 'MATERNAL', 'Protein: 1 egg, 1 glass milk, or 2 cups dal every day', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('bc54791b-fd65-512c-992c-17604b75bc7b', 'NUT-003', 'MATERNAL', 'Calcium: milk, curd, sesame seeds, ragi - supports fetal bone development', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('b2c4dc73-52a9-582e-96df-494660e3c437', 'NUT-004', 'MATERNAL', 'Avoid raw papaya, excess vitamin A (liver), unpasteurised dairy', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('c1d55fe8-7a4d-5652-b7a6-30cb71059f69', 'NUT-005', 'MATERNAL', 'Hydration: 8-10 glasses water/day; reduce salt to prevent BP rise', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('53142645-eb20-5f81-9b33-851bc23378dc', 'NUT-006', 'MATERNAL', 'Folic acid foods: leafy greens, legumes, citrus - especially in first trimester', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('6d79302a-79e6-5fd1-9e61-0430eea128c7', 'NUT-007', 'CHILD', '0-6 months: Exclusive breastfeeding only - no water, no formula', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('a46dfdd3-7e62-54b6-b43f-0d0a6669ca82', 'NUT-008', 'CHILD', '6-12 months: Mashed khichdi, dal-rice, banana, egg yolk 2-3 times/day', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('e7870ddd-a663-5dd0-be45-d2fca99ee8a3', 'NUT-009', 'CHILD', '12-24 months: Family foods (soft), 3 meals + 2 snacks; include eggs daily', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('a90b9ad0-fa7b-52f0-b813-28084f98d68e', 'NUT-010', 'CHILD', 'Avoid honey before 1 year, salt/sugar, junk food, sweetened drinks', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('fbbf4d1e-d433-590d-ab4c-45a9d5483c35', 'NUT-011', 'CHILD', 'Iron from green leafy vegetables, poha, ragi, meat', TRUE) ON CONFLICT (advice_id) DO NOTHING;
INSERT INTO dinc_metadata.nutrition_advice (advice_id, advice_code, category, advice_text, is_active) VALUES ('cdceeaf5-d036-5064-8858-4ec0b6c0999a', 'NUT-012', 'CHILD', 'Vitamin A: carrots, papaya, green leafy vegetables weekly', TRUE) ON CONFLICT (advice_id) DO NOTHING;
