INSERT INTO dinc_metadata.training_module (module_code, title, category, description, duration_minutes, content, is_active) VALUES ('TM001', 'Patient Communication Skills', 'Clinical Skills', 'Learn effective communication techniques for patient interaction.', 45, 'Active listening, empathy, clear communication, patient confidentiality, documentation, handling difficult situations, and building trust with patients.', TRUE) ON CONFLICT (module_code) DO NOTHING;
INSERT INTO dinc_metadata.training_module (module_code, title, category, description, duration_minutes, content, is_active) VALUES ('TM002', 'Emergency Response Training', 'Emergency Care', 'Respond effectively to medical emergencies.', 60, 'Emergency assessment, CPR basics, first aid skills, recovery position, emergency referral procedures, and emergency contact protocols.', TRUE) ON CONFLICT (module_code) DO NOTHING;
