INSERT INTO dinc_metadata.training_module (module_code, title, category, description, duration_minutes, content, is_active) VALUES ('TM004', 'Maternal Health Management', 'Maternal Health', 'Comprehensive maternal healthcare and safety.', 90, 'Antenatal care, nutrition during pregnancy, danger signs, labor preparation, postnatal care, and maternal health monitoring.', TRUE) ON CONFLICT (module_code) DO NOTHING;
INSERT INTO dinc_metadata.training_module (module_code, title, category, description, duration_minutes, content, is_active) VALUES ('TM005', 'Chronic Disease Management', 'Chronic Diseases', 'Management of diabetes, hypertension, and chronic conditions.', 75, 'Diabetes care, hypertension management, asthma care, COPD management, medication adherence, lifestyle counselling, and complication prevention.', TRUE) ON CONFLICT (module_code) DO NOTHING;
